using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    // Define the order of business lines
    vector<string> businessOrder = {"electronics", "grocery", "pharmacy", "restaurant"};

    // Filter valid coupons based on the conditions
    vector<pair<string, string>> validCoupons;
    for (size_t i = 0; i < code.size(); ++i) {
        if (code[i].empty() || !std::all_of(code[i].begin(), code[i].end(), 
            [](char c) { return isalnum(c) || c == '_'; })) {
            continue;
        }
        if (businessLine[i] == "electronics" || businessLine[i] == "grocery" ||
            businessLine[i] == "pharmacy" || businessLine[i] == "restaurant") {
            if (isActive[i]) {
                validCoupons.push_back({code[i], businessLine[i]});
            }
        }
    }

    // Sort the valid coupons first by business line order, then by code dictionary order
    sort(validCoupons.begin(), validCoupons.end(), 
        [](const pair<string, string>& a, const pair<string, string>& b) {
            size_t idxA = find(businessOrder.begin(), businessOrder.end(), a.second) - businessOrder.begin();
            size_t idxB = find(businessOrder.begin(), businessOrder.end(), b.second) - businessOrder.begin();
            if (idxA != idxB) {
                return idxA < idxB;
            }
            return a.first < b.first;
        });

    // Extract the codes from the sorted valid coupons
    vector<string> result;
    for (const auto& coupon : validCoupons) {
        result.push_back(coupon.first);
    }

    return result;
}
